public async Task<bool> PurchaseTicketsAsync(int eventId, int purchaseQuantity)
{
    using (var dbContext = new BookingContext())
    {
        // Enable high concurrency handling
        var eventEntity = await dbContext.Events
            .AsNoTracking()
            .FirstOrDefaultAsync(e => e.EventId == eventId);

        if (eventEntity == null)
            return false; // Event not found

        if (purchaseQuantity <= 0 || purchaseQuantity > eventEntity.AvailableSeats)
            return false; // Invalid quantity or not enough seats

        // Run the operation in a retry loop to handle concurrency
        var success = false;
        while (!success)
        {
            try
            {
                eventEntity.AvailableSeats -= purchaseQuantity;
                dbContext.Events.Update(eventEntity);
                await dbContext.SaveChangesAsync();
                success = true;
            }
            catch (DbUpdateConcurrencyException)
            {
                // Refresh event data due to concurrency conflict
                var entry = dbContext.Entry(eventEntity);
                entry.Reload();
            }
        }

        return true; // Purchase successful
    }
